public class BankingApp extends AppCompatActivity {
    private static final int REQUEST_CODE = 100;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking_app);

        // Setup UI elements
        Button transactionButton = findViewById(R.id.transaction_button);
        TextView accountBalanceTextView = findViewById(R.id.account_balance);

        // Setup transaction button click listener
        transactionButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                // Launch transaction processing activity
                startActivityForResult(new Intent(BankingApp.this, TransactionProcessingActivity.class), REQUEST_CODE);
            }
        });

        // Setup account balance display update listener
        accountBalanceTextView.addTextChangedListener(new TextWatcher() {
            @Override
            public void beforeTextChanged(CharSequence s, int start, int count, int after) {
                // Do nothing
            }

            @Override
            public void onTextChanged(CharSequence s, int start, int before, int count) {
                // Update account balance based on text change
                String newBalance = s.subSequence(start, start + count).toString();
                updateAccountBalance(newBalance);
            }

            @Override
            public void afterTextChanged(Editable s) {
                // Do nothing
            }
        });
    }

    private void updateAccountBalance(String newBalance) {
        // Update account balance in your database or wherever it is stored
        // For now, we'll just display the new balance on screen
        TextView accountBalanceTextView = findViewById(R.id.account_balance);
        accountBalanceTextView.setText("$" + newBalance);
    }
}